prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?origId ?normId ?created WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  OPTIONAL { ?model tai:modelCreated ?created . }
  FILTER(STR(?origId) = "262d9e9b8c224d918fe800cd2a454ddf" || STR(?normId) = "262d9e9b8c224d918fe800cd2a454ddf")
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?choreo ?choreoName (COUNT(DISTINCT ?task) AS ?taskCount)
       (COUNT(DISTINCT ?gw) AS ?gatewayCount)
       (COUNT(DISTINCT ?evt) AS ?eventCount)
       (COUNT(DISTINCT ?flows) AS ?flowEdgeCount)
WHERE {
  ?model a bboExt:Model .
  FILTER(STR(?model) = "https://www.teamingai-project.eu/kg/model/sid_ece51571_13ba_41d8_8688_057c876cc093")
  ?model tai:belongsTo ?org .
  ?model bbo:name ?modelName .
  ?def tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ; tai:belongsTo ?def .

  OPTIONAL { ?task a bboExt:ChoreographyTask ; tai:belongsTo ?choreo . }
  OPTIONAL { ?gw a bboExt:ExclusiveGateway ; tai:belongsTo ?choreo . }
  OPTIONAL { ?gw2 a bboExt:ParallelGateway ; tai:belongsTo ?choreo . }
  OPTIONAL { ?gw3 a bboExt:EventBasedGateway ; tai:belongsTo ?choreo . }
  OPTIONAL {
    ?evt a bboExt:StartEvent , bboExt:EndEvent ; tai:belongsTo ?choreo .
  }
  OPTIONAL {
    ?evt a ?evtType ; tai:belongsTo ?choreo .
    FILTER(?evtType IN (bboExt:StartEvent, bboExt:IntermediateCatchEvent, bboExt:EndEvent))
  }
  OPTIONAL { ?flows a bbo:SequenceFlow ; tai:belongsTo ?choreo . }

  OPTIONAL { ?choreo bbo:name ?choreoName . }
}
GROUP BY ?choreo ?choreoName
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?elemType ?elem ?name
       (SAMPLE(?loopType) AS ?loopType)
       (SAMPLE(?initPartName) AS ?initiatingParticipant)
       (SAMPLE(?gateDir) AS ?gatewayDirection)
       (SAMPLE(?inst) AS ?eventInstantiated)
       (SAMPLE(?eventGwType) AS ?eventGatewayType)
WHERE {
  ?model a bboExt:Model .
  FILTER(STR(?model) = "https://www.teamingai-project.eu/kg/model/sid_ece51571_13ba_41d8_8688_057c876cc093")
  ?model tai:belongsTo ?org .
  ?def tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ; tai:belongsTo ?def .

  ?elem a ?elemType .
  VALUES ?elemType { bboExt:ChoreographyTask bboExt:ExclusiveGateway bboExt:ParallelGateway bboExt:EventBasedGateway bboExt:StartEvent bboExt:IntermediateCatchEvent bboExt:EndEvent }
  ?elem tai:belongsTo ?choreo .
  OPTIONAL { ?elem bbo:name ?name . }

  OPTIONAL {
    ?elem a bboExt:ChoreographyTask .
    OPTIONAL { ?elem bboExt:loopType ?loopType . }
    OPTIONAL {
      ?elem bboExt:initiatingParticipantRef ?partRef .
      ?part a bboExt:Participant ; tai:belongsTo ?choreo .
      FILTER(STRENDS(STR(?part), ?partRef))
      OPTIONAL { ?part bbo:name ?initPartName . }
    }
  }

  OPTIONAL {
    ?elem a bboExt:ExclusiveGateway ; bboExt:gatewayDirection ?gateDir .
  }
  OPTIONAL {
    ?elem a bboExt:EventBasedGateway ; bboExt:isImmediate ?inst .
  }
  OPTIONAL {
    ?elem a bboExt:EventBasedGateway ; bboExt:eventGatewayType ?eventGwType .
  }
}
GROUP BY ?elemType ?elem ?name
ORDER BY ?elemType ?name
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?elemType ?elem ?name ?loopType ?initiatingParticipant ?gatewayDirection ?isImmediate ?eventGatewayType WHERE {
  ?model a bboExt:Model .
  FILTER(STR(?model) = "https://www.teamingai-project.eu/kg/model/sid_ece51571_13ba_41d8_8688_057c876cc093")

  ?model tai:belongsTo ?org .
  ?def tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ; tai:belongsTo ?def .

  ?elem tai:belongsTo ?choreo .
  VALUES ?elemType { 
    bboExt:ChoreographyTask 
    bboExt:ExclusiveGateway 
    bboExt:ParallelGateway 
    bboExt:EventBasedGateway 
    bboExt:StartEvent 
    bboExt:IntermediateCatchEvent 
    bboExt:EndEvent
  }
  ?elem a ?elemType .

  OPTIONAL { ?elem bbo:name ?name . }

  OPTIONAL {
    ?elem a bboExt:ChoreographyTask ; bboExt:loopType ?loopType .
  }

  OPTIONAL {
    ?elem a bboExt:ChoreographyTask ; bboExt:initiatingParticipantRef ?partRef .
    ?part a bboExt:Participant ; tai:belongsTo ?choreo .
    FILTER(STRENDS(STR(?part), ?partRef))
    OPTIONAL { ?part bbo:name ?initiatingParticipant . }
  }

  OPTIONAL {
    ?elem a bboExt:ExclusiveGateway ; bboExt:gatewayDirection ?gatewayDirection .
  }
  OPTIONAL {
    ?elem a bboExt:EventBasedGateway ; bboExt:isImmediate ?isImmediate .
  }
  OPTIONAL {
    ?elem a bboExt:EventBasedGateway ; bboExt:eventGatewayType ?eventGatewayType .
  }
}
LIMIT 25
